import { createBrowserRouter, RouterProvider, useParams } from "react-router-dom";
import oidcConfig from "./OIDCConfig";
import { AuthenticationProvider } from "./AuthService";
import { AuthProvider as OIDCAuthProvider } from "react-oidc-context";
import { Protected } from "./components/ProtectedRoute.component";
import { HomePageComponent } from "./pages/Home.page";
import { MapEditorPageComponent } from "./pages/MapEditor.page";
import { NodeTemplateEditorPageComponent } from "./pages/NodeTemplateEditor.page";
import { MapCreatorPageComponent } from "./pages/MapCreator.page";
import { LibraryPageComponent } from "./pages/Library.page";
import { DatasetCreatorPageComponent } from "./pages/DatasetCreator.page";
import { DatasetEditorPageComponent } from "./pages/DatasetEditor.page";
import { LoginPageComponent } from "./pages/Login.page";
import { ErrorPage } from "./pages/Error.page";
import { SettingsPageComponent } from "./pages/Settings.page";
import Layout from "./Layout";

// Wrapper that keys MapEditorPageComponent on the mapId param so React
// remounts (rather than reuses) the component when navigating between maps.
function MapEditorRoute() {
    const { mapId } = useParams();
    return <MapEditorPageComponent key={mapId} />;
}

// Same pattern for the dataset editor.
function DatasetEditorRoute() {
    const { datasetId } = useParams();
    return <DatasetEditorPageComponent key={datasetId} />;
}

function App() {
    const router = createBrowserRouter([
        {
            path: "/",
            element: <Layout />,
            errorElement: <ErrorPage />,
            children: [
                {
                    path: "/",
                    element: (
                        <Protected>
                            <HomePageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "map/new/",
                    element: (
                        <Protected>
                            <MapCreatorPageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "map/:mapId/",
                    element: (
                        <Protected>
                            <MapEditorRoute />
                        </Protected>
                    ),
                },
                {
                    path: "template/new",
                    element: (
                        <Protected>
                            <NodeTemplateEditorPageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "template/:templateId",
                    element: (
                        <Protected>
                            <NodeTemplateEditorPageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "dataset/new/",
                    element: (
                        <Protected>
                            <DatasetCreatorPageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "/dataset/:datasetId",
                    element: (
                        <Protected>
                            <DatasetEditorRoute />
                        </Protected>
                    ),
                },
                {
                    path: "/library/:datatype",
                    element: (
                        <Protected>
                            <LibraryPageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "/settings",
                    element: (
                        <Protected>
                            <SettingsPageComponent />
                        </Protected>
                    ),
                },
                {
                    path: "logout",
                    element: <LoginPageComponent doLogout={true} message="Logging out..." />,
                },
                {
                    path: "login",
                    element: <LoginPageComponent next="/" />,
                },
            ],
        },
    ]);
    return (
        <>
            <div className="App packets-ui">
                <OIDCAuthProvider {...oidcConfig}>
                    <AuthenticationProvider>
                        <RouterProvider router={router} />
                    </AuthenticationProvider>
                </OIDCAuthProvider>
            </div>
        </>
    );
}

export default App;
